```class Solution {
    public boolean isRationalEqual(String s, String t) {
        int[] sDigits = new int[4];
        int[] tDigits = new int[4];

        for (int i = 0; i < s.length(); i++) {
            sDigits[s.charAt(i)]++;
        }

        for (int i = 0; i < t.length(); i++) {
            tDigits[t.charAt(i)]++;
        }

        for (int i = 0; i < sDigits.length; i++) {
            if (sDigits[i] != tDigits[i]) {
                return false;
            }
        }

        for (int i = 0; i < tDigits.length; i++) {
            if (tDigits[i] != sDigits[i]) {
                return false;
            }
        }

        return true;
    }
}
